85: 	if err != nil {
86: 		return nil, err
87: 	}
88: 	if secret, ok := object.(*v1.Secret); ok {
89: 		return secret, nil
90: 	}
91: 	return nil, fmt.Errorf("unexpected object type: %v", object)
92: }
