131: func warningsForSecret(secret *api.Secret) []string {
132: 	var warnings []string
133: 	if secret.Type == api.SecretTypeTLS {
134: 		// Verify that the key matches the cert.
135: 		_, err := tls.X509KeyPair(secret.Data[api.TLSCertKey], secret.Data[api.TLSPrivateKeyKey])
136: 		if err != nil {
137: 			warnings = append(warnings, err.Error())
138: 		}
139: 	}
140: 	return warnings
